并查集 (DSU):
class DSU:
    def __init__(self, n):
        self.parent = list(range(n + 1))
    def find(self, i):
        if self.parent[i] == i: return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]
    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)
        if root_i != root_j: self.parent[root_i] = root_j

